export interface BillingSummary {
  /** The user's current subscription plan. */
  currentPlan: string;
  /** The date of the next scheduled invoice, in ISO 8601 format (YYYY-MM-DD). */
  nextInvoiceDate: string;
  /** The total amount of money spent by the user over their lifetime, in USD. */
  lifetimeSpend: number;
  /** Any outstanding credit the user has, in USD. */
  outstandingCredit: number;
}
```
```aether:src/services/billing.ts
import { BillingSummary } from '../types';

/**
 * Simulates fetching billing summary data for a given user.
 * In a real application, this would interact with a database or a third-party billing API.
 *
 * @param userId The ID of the user for whom to fetch the billing summary.
 * @returns A promise that resolves to the BillingSummary object.
 */
export async function getBillingSummaryForUser(userId: string): Promise<BillingSummary> {
  console.log(`[BillingService] Fetching billing summary for user: ${userId}`);

  // Simulate a network delay or database query time
  await new Promise(resolve => setTimeout(resolve, 150));

  // Generate mock data for demonstration purposes
  const now = new Date();
  // Set next invoice date to the 15th of the next month
  const nextMonth = new Date(now.getFullYear(), now.getMonth() + 1, 15);
  const nextInvoiceDate = nextMonth.toISOString().split('T')[0]; // Format as YYYY-MM-DD

  return {
    currentPlan: 'Premium Pro',
    nextInvoiceDate: nextInvoiceDate,
    lifetimeSpend: 2500.50,
    outstandingCredit: 75.25,
  };
}
```
```aether:src/index.ts
import { Hono } from 'hono';
import { getBillingSummaryForUser } from './services/billing';
import { BillingSummary } from './types';

const app = new Hono();

/**
 * Root route for basic API health check.
 */
app.get('/', (c) => {
  return c.text('Hono Billing Summary Loader API is running!');
});

/**
 * Loader route to fetch the billing summary for the current user.
 *
 * This route returns the current plan, next invoice date, lifetime spend,
 * and any outstanding credit. The response is cached for 60 seconds.
 */
app.get('/billing-summary', async (c) => {
  // In a real application, the user ID would be extracted from an
  // authentication token or session. For this exercise, we use a placeholder.
  const userId = 'current-authenticated-user-id'; // Example placeholder user ID

  try {
    const summary: BillingSummary = await getBillingSummaryForUser(userId);

    // Set Cache-Control header to cache the response for 60 seconds.
    // 'public' allows caching by any cache (browser, CDN, proxy).
    // 'max-age=60' specifies the maximum amount of time (in seconds)
    // a resource is considered fresh.
    c.header('Cache-Control', 'public, max-age=60');

    return c.json(summary);
  } catch (error) {
    console.error(`[API Error] Failed to fetch billing summary for user ${userId}:`, error);
    // Return a 500 Internal Server Error with a generic message
    return c.json({ error: 'Failed to retrieve billing summary due to an internal error.' }, 500);
  }
});

export default app;
```

